#!/usr/bin/env python3
"""
Phase System Frontend Update
Run this from your ~/seller-portal directory:
    python3 update_phase_frontend.py
"""
import base64, os, sys

if not os.path.exists("frontend/src/pages"):
    print("Error: Run this from your ~/seller-portal directory")
    sys.exit(1)

files = {}
files["frontend/src/pages/AdminPropertyDetail.jsx"] = ""
files["frontend/src/pages/ClientDashboard.jsx"] = ""

for path, data in files.items():
    content = base64.b64decode(data)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(content)
    print(f"Updated: {path} ({len(content):,} bytes)")

print()
print("Done! Now run:")
print("  cd frontend && npm run dev    # to test locally")
print("  # or")
print("  git add -A && git commit -m \"Phase system frontend update\" && git push    # to deploy")
